            case 1 -> "Pancakes";
            case 2 -> "Tacos";
            case 3 -> "Ice cream";
            default -> "Mystery meal";
        };
        System.out.println("You picked option " + choice);
        System.out.println("Enjoy your " + meal + "!");
    }
}
